sql:
SELECT students.gpa, students.student_label
FROM students
WHERE students.student_id IN (SELECT student_id FROM student_sports);

SELECT DISTINCT coast
FROM students
WHERE university_year = 'frosh' AND early_bird_night_owl = 'night owl';

SELECT AVG(gpa)
FROM students
WHERE student_id IN (SELECT DISTINCT student_id FROM games);

SELECT (julianday(end_date) - julianday(start_date)) AS participation_duration
FROM student_sports
WHERE student_id = 123 AND sport_id = 123;

SELECT COUNT(game_id) AS Games_Played
FROM games
WHERE student_id IN (
  SELECT student_id FROM students WHERE gpa > 3.5
);

SELECT g.student_id, g.game_score
FROM games g
WHERE g.game_score > (SELECT AVG(game_score) FROM games);

